import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { query } from '../../config/neon';
import { getTrendPercentage, hasHistoricalData, recordUserMetrics } from '../../config/neonQueries';
import {
    Users,
    Disc,
    DollarSign,
    Calendar,
    TrendingUp,
    Plus,
    Music,
    Upload,
    BarChart3,
    ArrowRight,
    Activity,
    UserPlus,
    Briefcase,
    ChevronRight,
    Building2
} from 'lucide-react';
import ExternalArtistManager from './ExternalArtistManager';

/**
 * Metrics data interface
 */
interface LabelMetrics {
    totalArtists: number;
    activeReleases: number;
    monthlyRevenue: number;
    upcomingReleases: number;
    revenueGrowth: number;
    totalStreams: number;
}

/**
 * Artist roster data interface
 */
interface ArtistRosterData {
    id: string;
    artist_id: string;
    name: string;
    email?: string;
    photo_url?: string;
    status?: string;
    signed_date?: string;
    streams?: number;
    earnings?: number;
    last_release?: string;
    [key: string]: any;
}

/**
 * Release data interface
 */
interface ReleaseData {
    id: string;
    title: string;
    type?: string;
    release_date: string;
    cover_art_url?: string;
    artist_name?: string;
    [key: string]: any;
}

/**
 * LabelDashboard props
 */
export interface LabelDashboardProps {
    user?: any;
    userData?: any;
}

/**
 * LabelDashboard - Professional label management dashboard
 *
 * Displays:
 * - Overview metrics (artists, releases, revenue, deadlines)
 * - Roster performance table
 * - Release calendar
 * - Quick action buttons
 */
export default function LabelDashboard({ user, userData }: LabelDashboardProps) {
    const navigate = useNavigate();
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);
    const [metrics, setMetrics] = useState<LabelMetrics>({
        totalArtists: 0,
        activeReleases: 0,
        monthlyRevenue: 0,
        upcomingReleases: 0,
        revenueGrowth: 0,
        totalStreams: 0
    });
    const [revenueTrend, setRevenueTrend] = useState<string | null>(null);
    const [hasTrendData, setHasTrendData] = useState<boolean>(false);
    const [rosterData, setRosterData] = useState<ArtistRosterData[]>([]);
    const [upcomingReleases, setUpcomingReleases] = useState<ReleaseData[]>([]);
    const [artistView, setArtistView] = useState<'platform' | 'external'>('platform');

    const userId = user?.id || user?.uid || user?.userId;

    useEffect(() => {
        if (!userId) return;
        fetchDashboardData();
    }, [userId]);

    const fetchDashboardData = async () => {
        setLoading(true);
        setError(null);
        try {
            // Fetch all data in parallel
            const [artistsResult, releasesResult, revenueResult] = await Promise.all([
                // Get label roster count
                query(`
                  SELECT COUNT(*) as count
                  FROM label_roster
                  WHERE label_id::text = $1 AND status = 'active'
                `, [userId]).catch((e: Error) => {
                    console.warn('label_roster table not available:', e.message);
                    return [{ count: 0 }];
                }),

                // Get active releases
                query(`
                  SELECT COUNT(*) as count
                  FROM releases
                  WHERE label_id::text = $1 AND status IN ('distributed', 'submitted')
                `, [userId]).catch((e: Error) => {
                    console.warn('releases table not available:', e.message);
                    return [{ count: 0 }];
                }),

                // Get revenue data - using columns that exist in schema
                query(`
                  SELECT
                    COALESCE(SUM(lifetime_earnings), 0) as total_revenue,
                    COALESCE(SUM(lifetime_streams), 0) as total_streams
                  FROM distribution_stats
                  WHERE user_id::text IN (
                    SELECT artist_id::text FROM label_roster WHERE label_id::text = $1
                  )
                `, [userId]).catch((e: Error) => {
                    console.warn('distribution_stats table not available:', e.message);
                    return [{ total_revenue: '0', total_streams: '0' }];
                })
            ]);

            // Set metrics
            const monthlyRevenue = parseFloat(revenueResult[0]?.total_revenue || 0);
            setMetrics({
                totalArtists: parseInt(artistsResult[0]?.count || 0),
                activeReleases: parseInt(releasesResult[0]?.count || 0),
                monthlyRevenue: monthlyRevenue,
                upcomingReleases: parseInt(releasesResult[0]?.count || 0),
                revenueGrowth: 0, // Will be updated from real trend data
                totalStreams: parseInt(revenueResult[0]?.total_streams || 0)
            });

            // Fetch real trend data
            try {
                const hasHistory = await hasHistoricalData(userId);
                setHasTrendData(hasHistory);

                if (hasHistory) {
                    const trend = await getTrendPercentage(userId, 'revenue', 30);
                    setRevenueTrend(trend);
                    // Update revenueGrowth for display
                    const trendValue = parseFloat(trend.replace('%', ''));
                    setMetrics(prev => ({ ...prev, revenueGrowth: Math.abs(trendValue) }));
                }

                // Record current metrics for future trend calculations
                await recordUserMetrics(userId);
            } catch (error) {
                console.warn('Failed to fetch trend data:', error);
            }

            // Fetch roster with performance data
            const rosterResult = await query(`
                SELECT
                  lr.id,
                  lr.artist_id,
                  cu.first_name || ' ' || cu.last_name as name,
                  cu.email,
                  cu.profile_photo_url as photo_url,
                  lr.status,
                  lr.signed_date,
                  COALESCE(SUM(ds.lifetime_streams), 0) as streams,
                  COALESCE(SUM(ds.lifetime_earnings), 0) as earnings,
                  MAX(r.created_at) as last_release
                FROM label_roster lr
                LEFT JOIN clerk_users cu ON cu.id = lr.artist_id
                LEFT JOIN distribution_stats ds ON ds.user_id::text = lr.artist_id::text
                LEFT JOIN releases r ON r.artist_id::text = lr.artist_id::text
                WHERE lr.label_id::text = $1
                GROUP BY lr.id, lr.artist_id, cu.first_name, cu.last_name, cu.email, cu.profile_photo_url, lr.status, lr.signed_date
                ORDER BY lr.signed_date DESC
                LIMIT 10
            `, [userId]).catch((e: Error) => {
                console.warn('Could not fetch roster details:', e.message);
                return [];
            });

            setRosterData((rosterResult || []) as ArtistRosterData[]);

            // Fetch upcoming releases
            const upcomingReleasesResult = await query(`
                SELECT
                  r.id,
                  r.title,
                  r.type,
                  r.release_date,
                  r.cover_art_url,
                  p.display_name as artist_name
                FROM releases r
                LEFT JOIN profiles p ON p.user_id::text = r.artist_id::text
                WHERE r.label_id::text = $1
                  AND r.release_date >= CURRENT_DATE
                ORDER BY r.release_date ASC
                LIMIT 5
            `, [userId]).catch((e: Error) => {
                console.warn('Could not fetch upcoming releases:', e.message);
                return [];
            });

            setUpcomingReleases((upcomingReleasesResult || []) as ReleaseData[]);

        } catch (error: any) {
            console.error('Error fetching dashboard data:', error);
            setError(error.message);
        } finally {
            setLoading(false);
        }
    };

    const formatCurrency = (value: number): string => {
        return new Intl.NumberFormat('en-US', {
            style: 'currency',
            currency: 'USD',
            minimumFractionDigits: 0,
            maximumFractionDigits: 0,
        }).format(value);
    };

    const formatNumber = (value: number): string => {
        return new Intl.NumberFormat('en-US', {
            notation: 'compact',
            maximumFractionDigits: 1,
        }).format(value);
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[50vh]">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="max-w-7xl mx-auto pb-20">
                <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-2xl p-6">
                    <h2 className="text-lg font-semibold text-red-900 dark:text-red-400 mb-2">Database Error</h2>
                    <p className="text-red-700 dark:text-red-300">{error}</p>
                    <p className="text-sm text-red-600 dark:text-red-400 mt-2">
                        The Label dashboard requires Neon database tables. Please run the SQL migration scripts.
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto pb-20">
            {/* Breadcrumb */}
            <div className="mb-6">
                <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400 mb-2">
                    <Briefcase size={14} />
                    <span>Business Center</span>
                    <ChevronRight size={14} />
                    <span className="text-gray-700 dark:text-gray-200">Label Manager</span>
                </div>
                <h1 className="text-3xl font-bold dark:text-white flex items-center gap-3">
                    <div className="w-12 h-12 bg-gradient-to-br from-purple-500 to-pink-600 rounded-xl flex items-center justify-center text-white">
                        <Building2 size={24} />
                    </div>
                    {userData?.labelName || userData?.profileName || 'Label Manager'}
                </h1>
            </div>

            {/* Metrics Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                {/* Total Artists */}
                <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700 p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm font-medium text-gray-600 dark:text-gray-400">Total Artists</p>
                            <p className="text-3xl font-bold text-gray-900 dark:text-white mt-2">{metrics.totalArtists}</p>
                        </div>
                        <div className="bg-blue-100 dark:bg-blue-900/30 p-3 rounded-full">
                            <Users className="h-6 w-6 text-blue-600 dark:text-blue-400" />
                        </div>
                    </div>
                </div>

                {/* Active Releases */}
                <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700 p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm font-medium text-gray-600 dark:text-gray-400">Active Releases</p>
                            <p className="text-3xl font-bold text-gray-900 dark:text-white mt-2">{metrics.activeReleases}</p>
                        </div>
                        <div className="bg-purple-100 dark:bg-purple-900/30 p-3 rounded-full">
                            <Disc className="h-6 w-6 text-purple-600 dark:text-purple-400" />
                        </div>
                    </div>
                </div>

                {/* Monthly Revenue */}
                <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700 p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm font-medium text-gray-600 dark:text-gray-400">Total Revenue</p>
                            <p className="text-3xl font-bold text-gray-900 dark:text-white mt-2">
                                {formatCurrency(metrics.monthlyRevenue)}
                            </p>
                            {hasTrendData && revenueTrend && metrics.monthlyRevenue > 0 && (
                                <p className={`text-sm mt-1 flex items-center ${revenueTrend.startsWith('-') ? 'text-red-600 dark:text-red-400' : 'text-green-600 dark:text-green-400'}`}>
                                    <TrendingUp className="h-4 w-4 mr-1" />
                                    {revenueTrend}
                                </p>
                            )}
                        </div>
                        <div className="bg-green-100 dark:bg-green-900/30 p-3 rounded-full">
                            <DollarSign className="h-6 w-6 text-green-600 dark:text-green-400" />
                        </div>
                    </div>
                </div>

                {/* Total Streams */}
                <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700 p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm font-medium text-gray-600 dark:text-gray-400">Total Streams</p>
                            <p className="text-3xl font-bold text-gray-900 dark:text-white mt-2">
                                {formatNumber(metrics.totalStreams)}
                            </p>
                        </div>
                        <div className="bg-orange-100 dark:bg-orange-900/30 p-3 rounded-full">
                            <Activity className="h-6 w-6 text-orange-600 dark:text-orange-400" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Quick Actions */}
            <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700 p-6 mb-8">
                <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Quick Actions</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    <button
                        onClick={() => navigate('/labels/roster')}
                        className="flex items-center justify-center px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                    >
                        <UserPlus className="h-5 w-5 mr-2 text-blue-600 dark:text-blue-400" />
                        <span className="font-medium text-gray-700 dark:text-gray-200">Add Artist</span>
                    </button>

                    <button
                        onClick={() => navigate('/labels/releases')}
                        className="flex items-center justify-center px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                    >
                        <Plus className="h-5 w-5 mr-2 text-purple-600 dark:text-purple-400" />
                        <span className="font-medium text-gray-700 dark:text-gray-200">New Release</span>
                    </button>

                    <button
                        onClick={() => navigate('/labels/royalties')}
                        className="flex items-center justify-center px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                    >
                        <Upload className="h-5 w-5 mr-2 text-green-600 dark:text-green-400" />
                        <span className="font-medium text-gray-700 dark:text-gray-200">Upload Royalties</span>
                    </button>

                    <button
                        onClick={() => navigate('/labels/campaigns')}
                        className="flex items-center justify-center px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                    >
                        <BarChart3 className="h-5 w-5 mr-2 text-orange-600 dark:text-orange-400" />
                        <span className="font-medium text-gray-700 dark:text-gray-200">New Campaign</span>
                    </button>
                </div>
            </div>

            {/* Roster Performance */}
            <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700 mb-8">
                <div className="p-6 border-b border-gray-200 dark:border-gray-700">
                    <div className="flex items-center justify-between">
                        <div>
                            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Artist Management</h2>
                            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Manage your signed artists</p>
                        </div>
                        <div className="flex items-center gap-3">
                            {/* View Toggle */}
                            <div className="flex bg-gray-100 dark:bg-gray-800 rounded-lg p-1">
                                <button
                                    onClick={() => setArtistView('platform')}
                                    className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${
                                        artistView === 'platform'
                                            ? 'bg-white text-gray-900 dark:bg-gray-700 dark:text-white shadow-sm'
                                            : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                                    }`}
                                >
                                    Platform Artists
                                </button>
                                <button
                                    onClick={() => setArtistView('external')}
                                    className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all flex items-center gap-1 ${
                                        artistView === 'external'
                                            ? 'bg-white text-gray-900 dark:bg-gray-700 dark:text-white shadow-sm'
                                            : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                                    }`}
                                >
                                    <UserPlus size={14} />
                                    External Artists
                                </button>
                            </div>
                            <button
                                onClick={() => navigate('/labels/roster')}
                                className="text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium text-sm flex items-center"
                            >
                                View All
                                <ArrowRight className="h-4 w-4 ml-1" />
                            </button>
                        </div>
                    </div>
                </div>

                {/* Platform Artists Table */}
                {artistView === 'platform' ? (
                    <div className="overflow-x-auto">
                        <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                            <thead className="bg-gray-50 dark:bg-gray-800">
                                <tr>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                                        Artist
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                                        Status
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                                        Monthly Streams
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                                        Revenue
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                                        Last Release
                                    </th>
                                </tr>
                            </thead>
                            <tbody className="bg-white dark:bg-[#2c2e36] divide-y divide-gray-200 dark:divide-gray-700">
                                {rosterData.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="px-6 py-12 text-center text-gray-500 dark:text-gray-400">
                                            <Users className="h-12 w-12 mx-auto mb-4 text-gray-400" />
                                            <p className="text-lg font-medium dark:text-white">No artists on roster</p>
                                            <p className="text-sm mt-1">Add your first artist to get started</p>
                                        </td>
                                    </tr>
                                ) : (
                                    rosterData.map((artist) => (
                                        <tr key={artist.id} className="hover:bg-gray-50 dark:hover:bg-white/5">
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="flex items-center">
                                                    <div className="flex-shrink-0 h-10 w-10">
                                                        {artist.photo_url ? (
                                                            <img
                                                                className="h-10 w-10 rounded-full"
                                                                src={artist.photo_url}
                                                                alt={artist.name}
                                                            />
                                                        ) : (
                                                            <div className="h-10 w-10 rounded-full bg-gray-300 dark:bg-gray-700 flex items-center justify-center">
                                                                <Users className="h-6 w-6 text-gray-500 dark:text-gray-400" />
                                                            </div>
                                                        )}
                                                    </div>
                                                    <div className="ml-4">
                                                        <div className="text-sm font-medium text-gray-900 dark:text-white">{artist.name}</div>
                                                        <div className="text-sm text-gray-500 dark:text-gray-400">{artist.email}</div>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                                                    artist.status === 'active'
                                                        ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
                                                        : 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300'
                                                }`}>
                                                    {artist.status || 'Active'}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-white">
                                                {formatNumber(artist.streams || 0)}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-white">
                                                {formatCurrency(artist.earnings || 0)}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                                                {artist.last_release
                                                    ? new Date(artist.last_release).toLocaleDateString()
                                                    : 'N/A'}
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <div className="p-6">
                        <ExternalArtistManager user={user} />
                    </div>
                )}
            </div>

            {/* Upcoming Releases */}
            <div className="bg-white dark:bg-[#2c2e36] rounded-2xl border dark:border-gray-700">
                <div className="p-6 border-b border-gray-200 dark:border-gray-700">
                    <div className="flex items-center justify-between">
                        <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Upcoming Releases</h2>
                        <div className="flex items-center text-gray-500 dark:text-gray-400">
                            <Calendar className="h-5 w-5 mr-2" />
                            <span className="text-sm">Release Calendar</span>
                        </div>
                    </div>
                </div>

                <div className="p-6">
                    {upcomingReleases.length === 0 ? (
                        <div className="text-center py-12">
                            <Music className="h-12 w-12 mx-auto mb-4 text-gray-400" />
                            <p className="text-lg font-medium text-gray-900 dark:text-white">No upcoming releases</p>
                            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Schedule your next release</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {upcomingReleases.map((release) => (
                                <div
                                    key={release.id}
                                    className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                                >
                                    <div className="flex items-center">
                                        <div className="flex-shrink-0 h-16 w-16 bg-gray-300 dark:bg-gray-700 rounded">
                                            {release.cover_art_url ? (
                                                <img
                                                    className="h-16 w-16 rounded object-cover"
                                                    src={release.cover_art_url}
                                                    alt={release.title}
                                                />
                                            ) : (
                                                <div className="h-16 w-16 rounded flex items-center justify-center">
                                                    <Disc className="h-8 w-8 text-gray-500 dark:text-gray-400" />
                                                </div>
                                            )}
                                        </div>
                                        <div className="ml-4">
                                            <p className="text-sm font-medium text-gray-900 dark:text-white">{release.title}</p>
                                            <p className="text-sm text-gray-500 dark:text-gray-400">{release.artist_name}</p>
                                            <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">{release.type}</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-sm font-medium text-gray-900 dark:text-white">
                                            {new Date(release.release_date).toLocaleDateString()}
                                        </p>
                                        <p className="text-xs text-gray-500 dark:text-gray-400">Release Date</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}
